import { useState } from 'react';import { useMutation,useQueryClient } from '@tanstack/react-query';import { useSearchParams } from 'react-router-dom';import { Alert } from '@/components/ui/alert';import { Button } from '@/components/ui/button';import { usePermissions } from '@/hooks/usePermissions';import { apiErrorMessage } from '@/lib/apiClient';import { vendorApi } from '../api/vendorApi';import { useSaveContact,useSuppliers,useVendorContacts } from '../api/useVendors';import { ContactForm } from '../components/ContactForm';import { ContactTable } from '../components/ContactTable';import { VendorModal } from '../components/VendorModal';import type { ContactFormValues,SupplierContact } from '../types';
export const ContactsPage=()=>{const [sp,setSp]=useSearchParams();const [editing,setEditing]=useState<SupplierContact|null|undefined>();const [selectedVendor,setSelectedVendor]=useState(0);const {can}=usePermissions();const client=useQueryClient();const filters={search:sp.get('search')||'',department:sp.get('department')||'',vendor_id:sp.get('vendor_id')||'',page:Number(sp.get('page')||1),per_page:25};const list=useVendorContacts(filters);const suppliers=useSuppliers({status:'active',per_page:100});const vendorId=editing?.vendor_id??selectedVendor;const save=useSaveContact(vendorId,editing?.id);const action=useMutation({mutationFn:async({contact,type}:{contact:SupplierContact;type:'delete'|'primary'|'emergency'})=>type==='delete'?vendorApi.deleteContact(contact.vendor_id,contact.id):vendorApi.designateContact(contact.vendor_id,contact.id,type),onSuccess:()=>void client.invalidateQueries({queryKey:['vendors']})});const set=(k:string,v:string)=>{const n=new URLSearchParams(sp);if(v)n.set(k,v);else n.delete(k);setSp(n);};const submit=async(v:ContactFormValues)=>{await save.mutateAsync(v);setEditing(undefined);};const contacts=list.data?.data.map(x=>x.attributes)??[];return <div className="space-y-5 text-slate-800 dark:text-slate-100"><header><p className="text-xs font-bold uppercase tracking-[.18em] text-indigo-600">Vendor Management</p><h1 className="mt-2 text-2xl font-bold">Supplier Contacts</h1><p className="mt-1 text-sm text-slate-500">Department, primary, and emergency contacts across all suppliers.</p></header><div className="flex flex-wrap gap-3 rounded-xl border bg-white p-4 dark:border-slate-700 dark:bg-slate-900"><input placeholder="Search contacts…" value={filters.search} onChange={e=>set('search',e.target.value)} className="h-10 min-w-56 rounded-lg border px-3 text-sm dark:border-slate-600 dark:bg-slate-800"/><input placeholder="Department" value={filters.department} onChange={e=>set('department',e.target.value)} className="h-10 rounded-lg border px-3 text-sm dark:border-slate-600 dark:bg-slate-800"/><select value={filters.vendor_id} onChange={e=>set('vendor_id',e.target.value)} className="h-10 rounded-lg border bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800"><option value="">All suppliers</option>{suppliers.data?.data.map(x=><option key={x.attributes.id} value={x.attributes.id}>{x.attributes.company_name}</option>)}</select>{can('vendors.create')?<div className="ml-auto flex gap-2"><select value={selectedVendor} onChange={e=>setSelectedVendor(Number(e.target.value))} className="h-10 rounded-lg border bg-white px-3 text-sm dark:border-slate-600 dark:bg-slate-800"><option value={0}>Select supplier</option>{suppliers.data?.data.map(x=><option key={x.attributes.id} value={x.attributes.id}>{x.attributes.company_name}</option>)}</select><Button disabled={!selectedVendor} onClick={()=>setEditing(null)}>Add Contact</Button></div>:null}</div>{list.error||action.error?<Alert variant="danger" title="Contact operation failed">{apiErrorMessage(list.error||action.error)}</Alert>:null}<section className="overflow-hidden rounded-xl border bg-white dark:border-slate-700 dark:bg-slate-900"><ContactTable contacts={contacts} isLoading={list.isLoading} onEdit={can('vendors.update')?c=>{setSelectedVendor(c.vendor_id);setEditing(c);}:undefined} onDelete={can('vendors.delete')?c=>{if(confirm(`Remove ${c.name}?`))action.mutate({contact:c,type:'delete'});}:undefined} onPrimary={can('vendors.manage')?c=>action.mutate({contact:c,type:'primary'}):undefined} onEmergency={can('vendors.manage')?c=>action.mutate({contact:c,type:'emergency'}):undefined}/></section>{editing!==undefined&&vendorId>0?<VendorModal title={editing?'Edit Contact':'Add Contact'} onClose={()=>setEditing(undefined)}><ContactForm contact={editing} onSubmit={v=>void submit(v)} onCancel={()=>setEditing(undefined)} isLoading={save.isPending}/></VendorModal>:null}</div>;};
